#ifndef TAPROOT_FINITE_REPEAT_COMMAND_HPP_
#define TAPROOT_FINITE_REPEAT_COMMAND_HPP_

#include "command.hpp"

namespace tap
{
namespace control
{
class FiniteRepeatCommand : public Command
{
public:
    FiniteRepeatCommand(Command* command, int repeatCount)
        : command(command),
          repeatTarget(repeatCount)
    {
        commandRequirementsBitwise = command->getRequirementsBitwise();
    }

    bool isReady() override { return command->isReady(); }

    void initialize() override
    {
        currentRepeatCount = 0;
        ended = false;

        command->initialize();
    }

    void execute() override
    {
        if (finished)
        {
            return;
        }

        if (ended)
        {
            command->end(false);
            currentRepeatCount++;

            if (currentRepeatCount >= repeatTarget)
            {
                finished = true;
                return;
            }

            command->initialize();
            ended = false;
        }

        command->execute();

        if (command->isFinished())
        {
            ended = true;
        }
    }

    void end(bool interrupted) override { command->end(interrupted); }

    bool isFinished() const override { return finished; }

    const char* getName() const override { return "finite repeat command"; }

    int getCurrentRepeatCount() const { return currentRepeatCount; }

private:
    Command* command;
    int repeatTarget;
    int currentRepeatCount = 0;
    bool ended = false;
    bool finished = false;
};

}  // namespace control
}  // namespace tap

#endif